import React from "react";

const products = [
  {
    id: 1,
    title: "Engineering Book",
    price: 300,
    description: "Physics book in good condition",
    image:
      "https://images.unsplash.com/photo-1516979187457-637abb4f9353?w=500",
  },
  {
    id: 2,
    title: "Scientific Calculator",
    price: 500,
    description: "Casio calculator for engineering students",
    image:
      "https://images.unsplash.com/photo-1509228468518-180dd4864904?w=500",
  },
  {
    id: 3,
    title: "Laptop Table",
    price: 700,
    description: "Portable study table for hostel",
    image:
      "https://images.unsplash.com/photo-1496181133206-80ce9b88a853?w=500",
  },
  {
    id: 4,
    title: "Gaming Headphones",
    price: 1200,
    description: "Good sound quality and mic",
    image:
      "https://images.unsplash.com/photo-1505740420928-5e560c06d30e?w=500",
  },
];

function App() {
  return (
    <div
      style={{
        fontFamily: "Arial, sans-serif",
        backgroundColor: "#f4f6f9",
        minHeight: "100vh",
      }}
    >
      {/* Navbar */}
      <nav
        style={{
          backgroundColor: "#2563eb",
          padding: "15px 30px",
          display: "flex",
          justifyContent: "space-between",
          alignItems: "center",
          color: "white",
        }}
      >
        <h2>CampusKart</h2>

        <input
          type="text"
          placeholder="Search products..."
          style={{
            padding: "10px",
            width: "300px",
            borderRadius: "5px",
            border: "none",
            outline: "none",
          }}
        />
      </nav>

      {/* Hero Section */}
      <div
        style={{
          textAlign: "center",
          padding: "40px 20px",
        }}
      >
        <h1
          style={{
            fontSize: "40px",
            color: "#222",
          }}
        >
          Student Marketplace
        </h1>

        <p
          style={{
            color: "#666",
            fontSize: "18px",
          }}
        >
          Buy and Sell Products Easily Inside Campus
        </p>
      </div>

      {/* Products */}
      <div
        style={{
          display: "flex",
          flexWrap: "wrap",
          justifyContent: "center",
          gap: "25px",
          padding: "20px",
        }}
      >
        {products.map((product) => (
          <div
            key={product.id}
            style={{
              backgroundColor: "white",
              width: "280px",
              borderRadius: "10px",
              overflow: "hidden",
              boxShadow: "0 4px 10px rgba(0,0,0,0.1)",
              transition: "0.3s",
            }}
          >
            <img
              src={product.image}
              alt={product.title}
              style={{
                width: "100%",
                height: "200px",
                objectFit: "cover",
              }}
            />

            <div style={{ padding: "15px" }}>
              <h2>{product.title}</h2>

              <p style={{ color: "#555" }}>
                {product.description}
              </p>

              <h3 style={{ color: "green" }}>
                ₹{product.price}
              </h3>

              <button
                style={{
                  width: "100%",
                  backgroundColor: "#2563eb",
                  color: "white",
                  padding: "12px",
                  border: "none",
                  borderRadius: "5px",
                  cursor: "pointer",
                  fontSize: "16px",
                }}
              >
                Contact Seller
              </button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

export default App;
